export declare enum ContentLayer {
  /** Main document body content. */
  Body = "body",
  /** Page/section header (running header). */
  Header = "header",
  /** Page/section footer (running footer). */
  Footer = "footer",
  /** Footnote content. */
  Footnote = "footnote",
}

/** JATS contributor with role. */
